@import "@content-factory/ui/globals.css";
@source "../node_modules/streamdown/dist/*.js";

/* Content Factory design tokens — mirrors docs/design/hack/project/tokens.css.
   Exposed as Tailwind 4 utilities (bg-bg, text-text-muted, border-magenta, ...). */
@theme inline {
	--color-bg: #0a0a0b;
	--color-elev-1: #111113;
	--color-elev-2: #16161a;
	--color-border: rgba(255, 255, 255, 0.08);
	--color-border-soft: rgba(255, 255, 255, 0.06);
	--color-border-strong: rgba(255, 255, 255, 0.14);
	--color-text: #ececee;
	--color-text-muted: #8a8a93;
	--color-text-dim: #5c5c66;
	--color-magenta: #e5267c;
	--color-magenta-soft: rgba(229, 38, 124, 0.14);
	--color-magenta-bg: rgba(229, 38, 124, 0.08);
	--color-green: #2d6a4f;
	--color-amber: #8b6b1f;
	--color-red: #7a2e2e;

	--color-background: var(--color-bg);
	--color-foreground: var(--color-text);
	--color-ring: var(--color-magenta);
}

/* Permanent-dark theme: override shadcn vars to design tokens in both :root
   and .dark so the app renders identically regardless of theme class. */
:root,
.dark {
	--background: #0a0a0b;
	--foreground: #ececee;
	--border: rgba(255, 255, 255, 0.08);
	--ring: #e5267c;
	--card: #111113;
	--card-foreground: #ececee;
	--input: rgba(255, 255, 255, 0.08);
	--popover: #16161a;
	--popover-foreground: #ececee;
	--muted: #16161a;
	--muted-foreground: #8a8a93;
}

body {
	background: var(--color-bg);
	color: var(--color-text);
}

.mono {
	font-family: var(--font-mono);
}

export function Header() {
	return (
		<header className="flex h-14 items-center justify-between border-[var(--color-border)] border-b px-6">
			<span className="font-medium text-[14px] text-[var(--color-text)] tracking-[-0.01em]">
				Content Factory
				<span className="text-[var(--color-magenta)]">.</span>
			</span>
			<div className="flex items-center gap-[14px]">
				<button
					type="button"
					className="inline-flex items-center gap-2 rounded-md border border-[var(--color-border)] bg-transparent py-[6px] pr-[10px] pl-3 text-[13px] text-[var(--color-text)] transition-[background-color,border-color] duration-[120ms] hover:border-[var(--color-border-strong)] hover:bg-[var(--color-elev-1)]"
				>
					<span
						className="inline-flex h-[14px] w-[14px] items-center justify-center rounded-[3px] border border-[var(--color-border)] font-semibold text-[9px] text-[var(--color-text-muted)]"
						style={{
							background: "linear-gradient(135deg,#2A2A30,#1B1B20)",
						}}
					>
						A
					</span>
					<span>Acme Co</span>
					<svg
						aria-hidden="true"
						width={12}
						height={12}
						viewBox="0 0 24 24"
						fill="none"
						stroke="currentColor"
						strokeWidth={1.5}
						strokeLinecap="round"
						strokeLinejoin="round"
					>
						<path d="m6 9 6 6 6-6" />
					</svg>
				</button>
				<span
					className="inline-flex h-7 w-7 items-center justify-center rounded-full border border-[var(--color-border)] font-semibold text-[11px]"
					style={{
						background: "linear-gradient(135deg,#2E1F2A,#3A2533)",
						color: "#E5C7D6",
					}}
				>
					MP
				</span>
			</div>
		</header>
	);
}

export default Header;

import { Button as ButtonPrimitive } from "@base-ui/react/button";
import { cn } from "@content-factory/ui/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";

const buttonVariants = cva(
	"group/button inline-flex shrink-0 select-none items-center justify-center whitespace-nowrap rounded-none border border-transparent bg-clip-padding font-medium text-xs outline-none transition-all focus-visible:border-ring focus-visible:ring-1 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-1 aria-invalid:ring-destructive/20 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0",
	{
		variants: {
			variant: {
				default: "bg-primary text-primary-foreground [a]:hover:bg-primary/80",
				outline:
					"border-border bg-background hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
				secondary:
					"bg-secondary text-secondary-foreground hover:bg-secondary/80 aria-expanded:bg-secondary aria-expanded:text-secondary-foreground",
				ghost:
					"hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:hover:bg-muted/50",
				destructive:
					"bg-destructive/10 text-destructive hover:bg-destructive/20 focus-visible:border-destructive/40 focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:focus-visible:ring-destructive/40 dark:hover:bg-destructive/30",
				link: "text-primary underline-offset-4 hover:underline",
			},
			size: {
				default:
					"h-8 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-2 has-data-[icon=inline-start]:pl-2",
				xs: "h-6 gap-1 rounded-none px-2 text-xs has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3",
				sm: "h-7 gap-1 rounded-none px-2.5 has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3.5",
				lg: "h-9 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-3 has-data-[icon=inline-start]:pl-3",
				icon: "size-8",
				"icon-xs": "size-6 rounded-none [&_svg:not([class*='size-'])]:size-3",
				"icon-sm": "size-7 rounded-none",
				"icon-lg": "size-9",
			},
		},
		defaultVariants: {
			variant: "default",
			size: "default",
		},
	},
);

function Button({
	className,
	variant = "default",
	size = "default",
	...props
}: ButtonPrimitive.Props & VariantProps<typeof buttonVariants>) {
	return (
		<ButtonPrimitive
			data-slot="button"
			className={cn(buttonVariants({ variant, size, className }))}
			{...props}
		/>
	);
}

export { Button, buttonVariants };

